"use client";

import { useState } from "react";
import { Navbar } from "@/components/Navbar";
import { Hero } from "@/components/Hero";
import { About } from "@/components/About";
import { Projects } from "@/components/Projects";
import { Skills } from "@/components/Skills";
import { Blog } from "@/components/Blog";
import { Contact } from "@/components/Contact";
import { Footer } from "@/components/Footer";
import { Preloader } from "@/components/Preloader";

export default function Home() {
  const [isLoaded, setIsLoaded] = useState(false);

  return (
    <>
      <Preloader onLoadingComplete={() => setIsLoaded(true)} />

      <main className="relative min-h-screen selection:bg-neutral-800 selection:text-white dark:selection:bg-neutral-200 dark:selection:text-black">
        {/* We can mount Navbar immediately as it has its own initial drop-in animation */}
        <Navbar />

        {/* Pass `isLoaded` back to Hero to start staggered animation exactly when ready */}
        <Hero isLoaded={isLoaded} />

        <About />
        <Projects />
        <Skills />
        <Blog />
        <Contact />
        <Footer />
      </main>
    </>
  );
}
